const input = $node["Webhook — Form Submission"].json.headline.toLowerCase();
const kb = items.map(i => i.json);

// Simple Keyword Match
const matches = kb.map(a => {
  const title = a.title || a["ARTICLE TITLE"] || "";
  const score = input.split(' ').filter(word => title.toLowerCase().includes(word) && word.length > 4).length;
  return { ...a, similarity_score: score };
}).sort((a, b) => b.similarity_score - a.similarity_score);

return matches.slice(0, 3);

const ai = JSON.parse($node["Groq — AI Analysis"].json.body);
const source = ($node["Webhook — Form Submission"].json.source || "").toUpperCase();

let verdict = ai.verdict;
let rule = "AI Standard";

// Apply 5 Cyberpunk Rules
if (source.includes('FABRICATED')) { verdict = 'FAKE'; rule = 'Rule 1: Fabricated Source'; }
else if (source.includes('VIRAL') && ai.sentiment_score > 6) { verdict = 'FAKE'; rule = 'Rule 2: High Sentiment Risk'; }
else if (source.includes('REUTERS') && ai.sentiment_score < 3) { verdict = 'REAL'; rule = 'Rule 3: Trusted Clean Source'; }
else if (ai.confidence > 70 && ai.verdict === 'FAKE') { verdict = 'FAKE'; rule = 'Rule 4: High Confidence Confirmation'; }
else if (source.includes('REUTERS') && ai.confidence < 35) { verdict = 'REAL'; rule = 'Rule 5: Trusted Source Low Confidence'; }

return { ...ai, verdict, rule_applied: rule, source_status: source.includes('REUTERS') ? 'TRUSTED' : 'UNKNOWN' };
